// Validate email format from form submission
const body = $json.body || $json;
const email = (body.email || '').trim().toLowerCase();

if (!email || !email.includes('@') || !email.includes('.')) {
  throw new Error('Invalid or missing email address');
}

// Pass through cleaned form data
return {
  json: {
    email,
    firstName: (body.firstName || '').trim(),
    lastName: (body.lastName || '').trim(),
    company: (body.company || '').trim(),
    source: body.source || 'web-form',
    message: body.message || '',
    submittedAt: new Date().toISOString()
  }
};

// Merge original form data with Lusha enrichment
const form = $('Validate Email').first().json;
const lusha = $json;
const hubspotResults = $('Check HubSpot Duplicate').first().json;
const isExisting = hubspotResults.total > 0;
const existingId = isExisting ? hubspotResults.results?.[0]?.id : null;

return {
  json: {
    // Identity
    email: form.email,
    firstName: form.firstName || lusha.firstName || '',
    lastName: form.lastName || lusha.lastName || '',

    // Lusha enrichment
    jobTitle: lusha.jobTitle || '',
    seniority: lusha.seniority || '',
    phone: lusha.primaryPhone || '',
    phoneType: lusha.primaryPhoneType || '',
    verifiedEmail: lusha.primaryEmail || '',
    linkedinUrl: lusha.linkedinProfile || '',

    // Company data
    company: form.company || lusha.companyName || '',
    companyDomain: lusha.companyDomain || '',
    companySize: lusha.companySize || '',
    industry: lusha.companyMainIndustry || '',
    revenueRange: lusha.revenueRange || '',
    companyLocation: lusha.companyLocation || '',

    // Metadata
    isExistingContact: isExisting,
    existingContactId: existingId,
    source: form.source,
    message: form.message,
    enrichedAt: new Date().toISOString(),
    enrichmentSource: 'lusha'
  }
};

